SELECT count(*) FROM cast_info, role_type, title, char_name, name, movie_info, movie_companies WHERE cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND movie_info.movie_id = title.id AND movie_companies.movie_id = title.id;